return [
  {
    json: {
      team1: 'Brasil',
      team2: 'Marruecos',
      person1Name: 'Nikito',
      person2Name: 'Noe',
      venue: 'MetLife Stadium',
      location: 'New York/New Jersey',
      person1Url: 'https://raw.githubusercontent.com/elyager/datos-del-mundial-2026/main/assets/images/people/yager.jpeg',
      person2Url: 'https://raw.githubusercontent.com/elyager/datos-del-mundial-2026/main/assets/images/people/nere.jpeg',
      team1ShirtUrl: 'https://store.fifa.com/cdn/shop/files/image_02047e33-3b4e-41f2-869b-ac361dd4b283.jpg',
      team2ShirtUrl: 'https://store.fifa.com/cdn/shop/files/image_54f59fd1-10b1-4430-b581-a46bbd87255c.jpg',
      templateUrl: 'https://picsum.photos/seed/world-cup-card-template/1024/1024',
    },
  },
];

const body = $json.body ?? $json;
const cardInput = { ...body };

const requiredFields = [
  'team1',
  'team2',
  'person1Name',
  'person2Name',
  'venue',
  'location',
  'person1Url',
  'person2Url',
  'team1ShirtUrl',
  'team2ShirtUrl',
  'templateUrl',
];

const missing = requiredFields.filter((field) => typeof cardInput[field] !== 'string' || !cardInput[field].trim());
if (missing.length) {
  throw new Error(`Card input is missing required fields: ${missing.join(', ')}`);
}

for (const field of requiredFields) {
  cardInput[field] = cardInput[field].trim();
}

const urlFields = ['person1Url', 'person2Url', 'team1ShirtUrl', 'team2ShirtUrl', 'templateUrl'];
const invalidUrls = [];
const publicImageUrlPattern = /^https?:\/\/\S+$/i;
for (const field of urlFields) {
  if (!publicImageUrlPattern.test(cardInput[field])) {
    invalidUrls.push(field);
  }
}

if (invalidUrls.length) {
  throw new Error(`Card input has invalid public image URLs: ${invalidUrls.join(', ')}`);
}

return [{ json: cardInput }];

const cardInput = $json;
const imagePrompt = `Create a realistic square 1024x1024 premium football matchup trading-card image.

Use references as follows:
- Ref 1: Person 1 identity (${cardInput.person1Name}), placed left. Preserve face, hair, skin tone, gender expression, body type, and recognizable features.
- Ref 2: Person 2 identity (${cardInput.person2Name}), placed right. Preserve face, hair, skin tone, gender expression, body type, and recognizable features.
- Ref 3: Team 1 shirt (${cardInput.team1}), worn naturally by Person 1.
- Ref 4: Team 2 shirt (${cardInput.team2}), worn naturally by Person 2.
- Ref 5: Trading-card style/layout.

Do not swap shirts. Treat refs 1-2 as identity references and refs 3-4 as clothing references. Blend identity, body, neck, shirt, lighting, shadows, perspective, skin texture, and color temperature into one coherent photorealistic sports portrait, not a collage or face-swap.

Respect each person’s exact natural skin tone, facial features, hair, age, proportions, gender expression, and body shape. Anatomy must be realistic: correct head size, neck, shoulders, torso, chest, arms, hands, posture, and clothing fit. Avoid oversized heads, floating heads, pasted faces, mismatched bodies, distorted limbs, or unnatural proportions.

Composition: ${cardInput.person1Name} on the left wearing the ${cardInput.team1} shirt; ${cardInput.person2Name} on the right wearing the ${cardInput.team2} shirt. Show both waist-up or mid-torso-up, facing each other in an intense football matchup pose. Place a large glossy metallic “VS” centered between them.

Team names: Display ${cardInput.team1} above Person 1 and ${cardInput.team2} above Person 2. Text must be large, crisp, readable, balanced near the top, and not over faces or hair. Use premium sports-broadcast typography matching the card style. Use Spanish team/country names when applicable, e.g. Brasil, Marruecos, Alemania, Estados Unidos.

Clothing: Shirts must look truly worn, with correct collar fit, shoulder seams, sleeve fit, fabric folds, wrinkles, shadows, body tension, and perspective. Adapt each shirt to the person’s real body shape.

Add one subtle realistic supporter accessory per person matching their team/country colors, such as a scarf, wristband, face-paint stripe, flag-colored detail, cap detail, or stadium item. Accessories must be secondary and must not cover faces, shirts, team names, or VS text.

Style/background: Premium realistic international football trading card, cinematic sports-promo look, dramatic night stadium, floodlights, blurred crowd, rim light, depth of field, subtle glowing particles, energetic major-match atmosphere at ${cardInput.venue}, ${cardInput.location}, high-end collectible finish. Polished, professional, photorealistic, not cartoonish.

Restrictions: No shirt swaps. No text over faces. No distorted faces, hands, bodies, shirts, or accessories. Do not alter skin tone, gender expression, body shape, or likeness. No hard cutout edges, mismatched lighting, inconsistent skin tones, unauthorized logos, federation crests, FIFA logos, sponsor logos, or trademarked badges unless already present in the references.

Prioritize realistic likeness, accurate skin tone, correct anatomy, natural clothing integration, gender/body accuracy, readable Spanish team names, subtle country accessories, and premium trading-card quality.`;

const openRouterRequest = {
  model: 'openai/gpt-5.4-image-2',
  modalities: ['image', 'text'],
  stream: false,
  image_config: {
    aspect_ratio: '1:1',
    image_size: '1K',
  },
  messages: [
    {
      role: 'user',
      content: [
        { type: 'text', text: imagePrompt },
        { type: 'image_url', image_url: { url: cardInput.person1Url } },
        { type: 'image_url', image_url: { url: cardInput.person2Url } },
        { type: 'image_url', image_url: { url: cardInput.team1ShirtUrl } },
        { type: 'image_url', image_url: { url: cardInput.team2ShirtUrl } },
        { type: 'image_url', image_url: { url: cardInput.templateUrl } },
      ],
    },
  ],
};

return [{ json: { ...cardInput, imagePrompt, openRouterRequest } }];

const response = $json;
const image = response.choices?.[0]?.message?.images?.[0];
const generatedImageDataUrl = image?.image_url?.url ?? image?.imageUrl?.url;

if (!generatedImageDataUrl) {
  throw new Error('OpenRouter did not return choices[0].message.images[0].image_url.url.');
}

const match = generatedImageDataUrl.match(/^data:(image\/[a-z0-9.+-]+);base64,(.+)$/i);
if (!match) {
  throw new Error('Generated image is not a base64 image data URL.');
}

const mimeType = match[1].toLowerCase();
const base64Data = match[2];
const extensionByMimeType = {
  'image/png': 'png',
  'image/jpeg': 'jpg',
  'image/jpg': 'jpg',
  'image/webp': 'webp',
};
const fileExtension = extensionByMimeType[mimeType] ?? 'png';
const fileName = `world-cup-card-${response.id ?? Date.now()}.${fileExtension}`;

return [
  {
    json: {
      generatedImageDataUrl,
      mediaBinaryProperty: 'data',
      fileName,
      mimeType,
      model: response.model ?? 'openai/gpt-5.4-image-2',
      responseId: response.id,
      usage: response.usage,
    },
    binary: {
      data: {
        data: base64Data,
        mimeType,
        fileName,
        fileExtension,
      },
    },
  },
];
